bomData.valueScript:
//====================================================================
// Get data for bomElements
//====================================================================

// Variables
let bomElements: ICT_tab_HardwareLibraryMapping[] = [];

// Find all hardware ID's
let hardwareID = GlobalFunc.find_HardwareLibraryMapping(partSelf.pa_HardwareId);
let hardwareID2 = GlobalFunc.find_HardwareLibraryMapping(partSelf.pa_HardwareId2);
let hardwareID3 = GlobalFunc.find_HardwareLibraryMapping(partSelf.pa_HardwareId3);
let hardwareID4 = GlobalFunc.find_HardwareLibraryMapping(partSelf.pa_HardwareId4);

// Add the hardware items
hardwareID.forEach((elem) => {
  bomElements = bomElements.concat(elem);
});

hardwareID2.forEach((elem) => {
  bomElements = bomElements.concat(elem);
});

hardwareID3.forEach((elem) => {
  bomElements = bomElements.concat(elem);
});

hardwareID4.forEach((elem) => {
  bomElements = bomElements.concat(elem);
});

//====================================================================
// Insert the hardware items
//====================================================================

bomElements.forEach(x => 
{  
  let HardwareElem = this.addbomout_Hardware();
  let HardwareInfo = GlobalFunc.find_HardwareLibrary(x.SupplierArticleNumber!, x.Supplier!)

  HardwareElem.bom_Supplier = HardwareInfo.in_Supplier;
  HardwareElem.bom_SupplierArticle = HardwareInfo.in_SupplierArticleNumber;
  HardwareElem.bom_Description1 = HardwareInfo.Description;
  HardwareElem.bom_Description2 = HardwareInfo.Description2;
  HardwareElem.bom_Color = HardwareInfo.Color;
  HardwareElem.bom_ElementCategory = HardwareInfo.Category;
  HardwareElem.bom_Length = HardwareInfo.Length;
  HardwareElem.bom_Width = HardwareInfo.Width;
  HardwareElem.bom_Thk = HardwareInfo.Thickness;
})
